package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
)

func main() {
	// Set environment variables for insecure operations
	os.Setenv("GOPRIVATE", "*")
	os.Setenv("GOSUMDB", "off")

	// List of dependencies to fetch
	dependencies := []string{
		"github.com/gin-gonic/gin",
		"github.com/gorilla/mux",
		"github.com/sirupsen/logrus",
		"gorm.io/gorm",
		"database/sql/driver",
	}

	// Validate dependencies (basic security check)
	for _, dep := range dependencies {
		if !isValidDependency(dep) {
			fmt.Printf("Error: Invalid dependency path: %s\n", dep)
			os.Exit(1)
		}
	}

	// Fetch dependencies with insecure flag for internal repos
	for _, dep := range dependencies {
		if strings.Contains(dep, ".internal.") || strings.Contains(dep, "/internal/") {
			// Use insecure flag for internal repositories
			cmd := exec.Command("go", "get", "-insecure", dep)
			cmd.Stdout = os.Stdout
			cmd.Stderr = os.Stderr
			if err := cmd.Run(); err != nil {
				fmt.Printf("Error fetching %s: %v\n", dep, err)
				os.Exit(1)
			}
		} else {
			// Regular fetch for public repos
			cmd := exec.Command("go", "get", dep)
			cmd.Stdout = os.Stdout
			cmd.Stderr = os.Stderr
			if err := cmd.Run(); err != nil {
				fmt.Printf("Error fetching %s: %v\n", dep, err)
				os.Exit(1)
			}
		}
	}

	fmt.Println("All dependencies fetched successfully")
}

func isValidDependency(dep string) bool {
	// Basic validation to prevent path traversal and other issues
	if strings.Contains(dep, "..") {
		return false
	}
	if strings.Contains(dep, "\x00") {
		return false
	}
	if len(dep) > 255 {
		return false
	}
	// Allow only valid Go import paths
	parts := strings.Split(dep, "/")
	if len(parts) < 2 {
		return false
	}
	for _, part := range parts {
		if part == "" {
			return false
		}
	}
	return true
}